const aiResponse = $input.first().json;
const message = aiResponse.message || '';
const messageLower = message.toLowerCase();

// ============================================================
// AI MESSAGE DETECTION - PRIMARY CHECK
// ============================================================
// CRITICAL: Messages generated by the AI agent should NEVER be tracked
// This prevents infinite loops and database pollution
// ============================================================

// 1. Check for AI-GENERATED MESSAGE patterns
const aiGeneratedPatterns = [
  '👋 welcome to your personal business assistant',
  'please select an option:',
  'i can help you manage',
  'reply with the number',
  '1️⃣', '2️⃣', '3️⃣', '4️⃣', '5️⃣', '6️⃣',
  '📅 meeting options',
  'please select how you\'d like to view',
  '✅ message sent successfully',
  '✅ meeting scheduled',
  '✅ meeting invitation sent',
  '✅ contact',
  'added successfully',
  'invitation sent',
  'has been sent',
  'has been scheduled',
  'has been added',
  'meeting 1:',
  'meeting 2:',
  'here are your',
  'no meetings found',
  'retrieved',
  'search results',
  'i found the following',
  'i found',
  '📬',
  '🔄 erp/crm update feature',
  'returning to main menu',
  'returning to menu',
  '📨 message preview',
  'this message will be sent to',
  '📅 meeting invitation preview',
  'this invitation will be sent to',
  'please reply \'yes\' to send',
  'please reply \'yes\' to confirm',
  'reply \'yes\' to send',
  'or \'no\' to cancel',
  'meeting details:',
  'meeting details summary:',
  'organized by:',
  'the meeting invitation has been sent',
  '━━━━━━━━━━━━━━━━━━━━━━━━━━━',
  'please provide:',
  'please provide the following',
  'i need the following information',
  'would you like to',
  'what would you like',
  'who would you like',
  'what is the',
  'which contact',
  'ready to add this contact',
  'contact not found'
];

// 2. Check for structured formatting (strong indicator of AI responses)
const hasMultipleBullets = (message.match(/•/g) || []).length >= 2;
const hasMultipleEmojis = (message.match(/[📅📨✅🔄👋💡📍📋📬]/g) || []).length >= 2;
const hasDecorators = message.includes('━━━━━━') || message.includes('═══════');
const hasStructuredNewlines = (message.match(/\n\n/g) || []).length >= 2;

// 3. Check message length (AI responses are typically longer than user input)
const isLongMessage = message.length > 200;

// 4. Check for AI pattern matches
const containsAIPattern = aiGeneratedPatterns.some(pattern => 
  messageLower.includes(pattern.toLowerCase())
);

// ============================================================
// FINAL AI MESSAGE DETECTION
// ============================================================
// A message is AI-generated if it matches ANY of these criteria:
const isAIGeneratedMessage = 
  containsAIPattern || // Contains known AI patterns
  (hasMultipleBullets && isLongMessage) || // Structured with bullets
  (hasMultipleEmojis && isLongMessage) || // Multiple emojis + long
  (hasDecorators) || // Has decorative lines
  (hasStructuredNewlines && isLongMessage) || // Well-formatted paragraphs
  (hasMultipleBullets && hasMultipleEmojis); // Structured formatting

// ============================================================
// THREAD TRACKING DECISION
// ============================================================
// AI-generated messages should NEVER be tracked
// This prevents them from being stored in message_threads table
// ============================================================

let shouldTrackThread = false;
let skipReason = null;

if (isAIGeneratedMessage) {
  // AI messages are NEVER tracked
  shouldTrackThread = false;
  skipReason = 'AI_GENERATED_MESSAGE';
} else {
  // For non-AI messages (actual user responses), apply normal tracking logic

  // Only track very specific question patterns that expect single answers
  const singleAnswerQuestions = [
    'who would you like to send a message to',
    'please provide their name',
    'what message would you like to send',
    'what is the meeting title',
    'what is the purpose',
    'what is the location'
  ];

  const isSingleAnswer = singleAnswerQuestions.some(pattern => 
    messageLower.includes(pattern)
  );

  // Even single-answer questions from AI shouldn't be tracked
  shouldTrackThread = isSingleAnswer && !isAIGeneratedMessage;
  skipReason = shouldTrackThread ? null : 'NOT_TRACKABLE_QUESTION';
}

// ============================================================
// RETURN RESULT
// ============================================================

return [{
  json: {
    ...aiResponse,
    shouldTrackThread: shouldTrackThread,
    isAIMessage: isAIGeneratedMessage,
    skipReason: skipReason,
    debug: {
      messageLength: message.length,
      containsAIPattern,
      hasMultipleBullets,
      hasMultipleEmojis,
      hasDecorators,
      hasStructuredNewlines,
      isLongMessage,
      isAIGeneratedMessage,
      finalDecision: shouldTrackThread,
      messagePreview: message.substring(0, 150)
    }
  }
}];

// Get agent data from the direct input (Get a row7 output)
