// Get message data from Switch2 node
let messageData = null;

try {
  messageData = $('Switch2').first().json;
} catch (e) {
  throw new Error('Could not find message data from Switch2 node');
}

// Validate required fields
if (!messageData || !messageData.messageId || !messageData.message_body) {
  throw new Error(`Invalid message data: ${JSON.stringify(messageData)}`);
}

if (!agentData || !agentData.id) {
  throw new Error(`Invalid agent data: ${JSON.stringify(agentData)}`);
}

// Determine if message is from agent (outgoing) or from customer (incoming)
const isFromAgent = messageData.isFromMe || false;

// Determine the actual sender and recipient based on message direction
const senderPhone = messageData.from;
const recipientPhone = messageData.to;
const customerPhone = isFromAgent ? recipientPhone : senderPhone;

return [{
  json: {
    // Core message data
    messageId: messageData.messageId,
    chatInput: messageData.message_body,
    messageBody: messageData.message_body,
    timestamp: messageData.timestamp,
    source: messageData.source,

    // Phone numbers and conversation
    senderPhone: senderPhone,
    recipientPhone: recipientPhone,
    customerPhone: customerPhone,
    conversationId: messageData.metadata?.conversationId || `${customerPhone}@s.whatsapp.net`,

    // Message metadata
    messageType: messageData.metadata?.messageType || 'text',
    isFromAgent: isFromAgent,
    isEmailResponse: messageData.email_response || false,

    // Agent data from Get a row7
