} else if (downloadedContent?.data) {
  // Object with data property (PDF.co format)
  extractedText = downloadedContent.data;
} else if (downloadedContent?.body) {
  // Object with body property
  extractedText = downloadedContent.body;
} else {
  // Fallback: stringify the entire object
  extractedText = JSON.stringify(downloadedContent);
}

// Get original file info from trigger
const originalFile = $('When Executed by Another Workflow').first().json;

// Build comprehensive metadata
metadata = {
  // File identification
  file_type: fileType,
  mimetype: originalFile.mimetype || '',

  // Source information
  message_id: originalFile.message_id || '',
  conversation_id: originalFile.conversation_id || '',
  sender_name: originalFile.sender_name || '',
  from_number: originalFile.from_number || '',
  timestamp: originalFile.timestamp || '',

  // URLs
  original_url: originalFile.media_url || '',
  extracted_url: extractionNode?.url || '',

  // Extraction metadata
  page_count: extractionNode?.pageCount || null,
  file_name: extractionNode?.name || '',
  processing_time: extractionNode?.processingTime || null,
  credits_used: extractionNode?.creditsUsed || null,

  // User context
  user_id: originalFile.user_id || '',
  agent_id: originalFile.agent_id || '',
  platform: originalFile.platform || 'whatsapp',

  // Error handling
  error: extractionNode?.error || null,
  extraction_success: extractionNode?.error ? false : true
};

// Clean up the text (remove excessive whitespace/newlines)
const cleanedText = extractedText
  .replace(/\r\n/g, '\n')           // Normalize line endings
  .replace(/\n{3,}/g, '\n\n')       // Max 2 consecutive newlines
  .replace(/[ \t]{2,}/g, ' ')       // Remove multiple spaces
  .trim();

// Character count for validation
const charCount = cleanedText.length;
const wordCount = cleanedText.split(/\s+/).length;

// Return standardized output
return {
  json: {
    // Extracted content
    extracted_text: cleanedText,

    // Statistics
    character_count: charCount,
    word_count: wordCount,

    // All metadata
    ...metadata,

    // Processing timestamp
    extracted_at: new Date().toISOString(),

    // Success flag
    has_content: charCount > 0
  }
};

// ============================================
// DETECT EMAIL RESPONSE KEYWORDS & EXTRACT UID
// ============================================

// Get input data
const inputData = $input.first().json;
const messageBody = inputData.body || '';

// ============================================
// EXTRACT UID FROM MESSAGE (IMPROVED)
// ============================================
let uid = null;

// Priority 1: Match "uid 39482", "uid:39482", "uid(39482)", "uid-39482"
const uidPattern1 = /uid[:\s\-_(]*(\d+)/i;
const match1 = messageBody.match(uidPattern1);
if (match1) {
  uid = match1[1];
}

// Priority 2: Match "for 39482", "draft for 39482", "email 39482"
if (!uid) {
  const uidPattern2 = /(?:for|draft\s+for|email|message|reply\s+to)\s+(\d+)/i;
  const match2 = messageBody.match(uidPattern2);
  if (match2) {
    uid = match2[1];
  }
}

// Priority 3: Match "#39482"
if (!uid) {
  const uidPattern3 = /#(\d+)/;
  const match3 = messageBody.match(uidPattern3);
  if (match3) {
    uid = match3[1];
  }
}

// Priority 4: Standalone 4–6 digit number (fallback)
if (!uid) {
  const uidPattern4 = /\b(\d{4,6})\b/;
  const match4 = messageBody.match(uidPattern4);
  if (match4) {
    uid = match4[1];
  }
}

// ============================================
// DETECT KEYWORDS
// ============================================

// Approval keywords
const approvalPattern =
  /\b(approved?|approve|yes|send|ok|okay|confirm|confirmed?|go ahead|proceed)\b/i;
const isApproved = approvalPattern.test(messageBody);

// Rejection keywords
const rejectionPattern =
  /\b(reject|rejected?|decline|declined?|cancel|cancelled?|no|don't send|do not send|stop|delete|removed?)\b/i;
const isRejected = rejectionPattern.test(messageBody);

// Edit / draft keywords
const editPattern =
  /\b(draft|drafts?|edit|edited?|editing|modify|change|update|revise|create|make)\b/i;
const needsEdit = editPattern.test(messageBody);

// ============================================
// DETERMINE USER ACTION
// ============================================
let userAction = 'no';

if (isApproved && !isRejected) {
  userAction = 'yes';
} else if (isRejected) {
  userAction = 'no';
} else if (needsEdit) {
  userAction = 'edit';
}

// ============================================
// BACKWARD-COMPAT RESPONSE FLAG
// ============================================
const responsePattern =
  /\b(approved?|approve|draft|drafts?|edit|edited?|editing|reject|rejected?|decline|cancel|cancelled?|delete|removed?|yes|no|send|ok|okay|confirm|create|make)\b/i;

const email_response = responsePattern.test(messageBody);

// ============================================
// OUTPUT
// ============================================
return [
  {
    json: {
      // Extracted UID
      uid,

      // Final action
      user_action: userAction,

      // Detailed flags
      is_approved: isApproved,
      is_rejected: isRejected,
      needs_edit: needsEdit,

      // Compatibility flag
      email_response,

      // Original message
      message_body: messageBody,

      // Original metadata (unaltered)
      source: inputData.source,
      messageId: inputData.messageId,
      from: inputData.from,
      to: inputData.to,
      timestamp: inputData.timestamp,
      isFromMe: inputData.isFromMe,
      agentId: inputData.agentId,
      userId: inputData.userId,
      metadata: inputData.metadata,
      headers: inputData.headers
    }
  }
];

