parameters.jsCode:
// ============================================================================
// COMPLETE AI AGENT OUTPUT HANDLER
// Parses output, validates, and prepares for message sending
// ============================================================================

const agentOutput = $input.item.json.output;

// ============================================================================
// HELPER FUNCTIONS
// ============================================================================

function extractJSON(text) {
  try {
    // Try to find JSON block
    const jsonMatch = text.match(/\{[\s\S]*"category"[\s\S]*\}/);
    if (jsonMatch) {
      return JSON.parse(jsonMatch[0]);
    }
    return JSON.parse(text);
  } catch (error) {
    console.error('JSON extraction failed:', error);
    return null;
  }
}

function manualExtraction(text) {
  const categoryMatch = text.match(/"category":\s*"([^"]+)"/);
  const contactMatch = text.match(/"generated_response_for_contact":\s*"((?:[^"\\]|\\.)*)"/);
  const ownerMatch = text.match(/"generated_response_for_owner":\s*(?:"((?:[^"\\]|\\.)*)"|null)/);

  return {
    category: categoryMatch ? categoryMatch[1] : 'general',
    generated_response_for_contact: contactMatch ? contactMatch[1].replace(/\\n/g, '\n').replace(/\\"/g, '"') : 'Thank you for your message.',
    generated_response_for_owner: ownerMatch && ownerMatch[1] ? ownerMatch[1].replace(/\\n/g, '\n').replace(/\\"/g, '"') : null
  };
}

function validateCategory(category) {
  const valid = ['general', 'informational', 'decision-required', 'meeting'];
  return valid.includes(category) ? category : 'general';
}

// ============================================================================
// PARSE AGENT OUTPUT
// ============================================================================

let parsedData = extractJSON(agentOutput);

if (!parsedData) {
  parsedData = manualExtraction(agentOutput);
}

// Validate and clean
parsedData.category = validateCategory(parsedData.category);
parsedData.generated_response_for_contact = parsedData.generated_response_for_contact || 'Thank you for your message.';

// Handle null/string "null" for owner message
if (parsedData.generated_response_for_owner === 'null' || parsedData.generated_response_for_owner === null) {
  parsedData.generated_response_for_owner = null;
}

// ============================================================================
// GET CONTEXT DATA
// ============================================================================

const context = {
  contactPhone: $('Prepare data').first().json.originalMessage.messageData.from,
  ownerPhone: $('Prepare data').item.json.originalMessage.messageData.to,
  contactName: $('Prepare data').item.json.originalMessage.senderName,
  ownerName: $('Prepare data').item.json.originalMessage.ownerName,
  agentId: $('Prepare data').item.json.originalMessage.messageData.agentId,
  messageBody: $('Prepare data').item.json.messageBody,
  timestamp: $('Prepare data').item.json.originalMessage.timestamp,
  conversationId: $('Prepare data').item.json.conversationId
};

// ============================================================================
// CATEGORY-SPECIFIC LOGIC
// ============================================================================

const categoryInfo = {
  general: {
    description: 'Casual conversation - Contact handled directly',
    shouldNotifyOwner: false,
    emoji: '💬'
  },
  informational: {
    description: 'Information provided - Conditional owner notification',
    shouldNotifyOwner: parsedData.generated_response_for_owner !== null,
    emoji: 'ℹ️'
  },
  'decision-required': {
    description: 'Decision needed - Owner will be notified after permission',
    shouldNotifyOwner: parsedData.generated_response_for_owner !== null,
    emoji: '🚨'
  },
  meeting: {
    description: 'Meeting related - Tool handles automatically',
    shouldNotifyOwner: parsedData.generated_response_for_owner !== null,
    emoji: '🗓️'
  }
};

const currentCategory = categoryInfo[parsedData.category] || categoryInfo.general;

// ============================================================================
// PREPARE OUTPUT
// ============================================================================

const output = {
  // Parsed data
  category: parsedData.category,
  categoryEmoji: currentCategory.emoji,
  categoryDescription: currentCategory.description,

  // Context
  contactPhone: context.contactPhone,
  ownerPhone: context.ownerPhone,
  contactName: context.contactName,
  ownerName: context.ownerName,
  agentId: context.agentId,
  conversationId: context.conversationId,

  // Original data
  originalMessage: context.messageBody,
  timestamp: context.timestamp,

  // Messages
  messageToContact: parsedData.generated_response_for_contact,
  messageToOwner: parsedData.generated_response_for_owner,

  // Routing flags
  shouldNotifyOwner: currentCategory.shouldNotifyOwner,
  shouldSendToContact: true, // Always send to contact

  // Ready-to-send objects
  contactMessage: {
    to: context.contactPhone,
    message: parsedData.generated_response_for_contact,
    agentId: context.agentId,
    category: parsedData.category,
    timestamp: new Date().toISOString()
  },

  ownerMessage: currentCategory.shouldNotifyOwner ? {
    to: context.ownerPhone,
    message: parsedData.generated_response_for_owner,
    agentId: context.agentId,
    category: parsedData.category,
    contactName: context.contactName,
    contactPhone: context.contactPhone,
    timestamp: new Date().toISOString()
  } : null,

  // Logging
  rawAgentOutput: agentOutput,
  parsedAt: new Date().toISOString(),

  // Summary for logging
  summary: `${currentCategory.emoji} ${parsedData.category.toUpperCase()} | From: ${context.contactName} | Owner notified: ${currentCategory.shouldNotifyOwner ? 'YES' : 'NO'}`
};

// ============================================================================
// LOG SUMMARY
// ============================================================================

console.log('='.repeat(60));
console.log('AI AGENT OUTPUT PARSED');
console.log('='.repeat(60));
console.log(`Category: ${output.categoryEmoji} ${output.category}`);
console.log(`Contact: ${output.contactName} (${output.contactPhone})`);
console.log(`Owner: ${output.ownerName} (${output.ownerPhone})`);
console.log(`Notify Owner: ${output.shouldNotifyOwner ? '✅ YES' : '❌ NO'}`);
console.log(`Message to Contact: "${output.messageToContact.substring(0, 50)}..."`);
if (output.messageToOwner) {
  console.log(`Message to Owner: "${output.messageToOwner.substring(0, 50)}..."`);
}
console.log('='.repeat(60));

return output;

