// ============================================
// DYNAMIC CONFIGURATION
// ============================================
const CONFIG = {
  emailNodeName: 'Email Triage AI Agent',
  agentNodeName: 'Get a row1',
  defaultPhone: '923359503935',

  fieldMappings: {
    uid: ['uid', 'email_uid', 'id', 'message_id'],
    priority: ['priority_display', 'priority', 'importance', 'urgency'],
    score: ['score', 'priority_score', 'rating'],
    summary: ['summary', 'email_summary', 'overview', 'description'],
    suggestedReply: ['suggested_reply', 'reply', 'response', 'draft_reply'],
    subject: ['subject', 'email_subject', 'title'],
    emailBody: ['email_body', 'body_text', 'body', 'content', 'message', 'text'],
    fromName: ['from_name', 'sender_name', 'sender', 'name'],
    fromEmail: ['from_email', 'sender_email', 'email', 'from'],
    receivedAt: ['received_at', 'timestamp', 'date', 'created_at'],
    emailType: ['email_type', 'type', 'category', 'classification'],
    agentId: ['id', 'agent_id', 'agentId', 'uuid'],
    phoneNumber: ['agent_phone_number', 'phone_number', 'phone', 'whatsapp_phone_number'],
    agentName: ['agent_name', 'name', 'bot_name']
  },

  priorityEmojis: {
    high: '🔴',
    medium: '🟡',
    low: '🟢',
    critical: '🔴',
    urgent: '🔴',
    normal: '🟡'
  }
};

// ============================================
// HELPER FUNCTIONS
// ============================================
function getNodeData(nodeName) {
  try {
    const data = $(nodeName).item.json;
    return data.output || data;
  } catch (error) {
    console.log(`Node "${nodeName}" not found`);
    return null;
  }
}

function getField(obj, fieldNames, defaultValue = '') {
  if (!obj) return defaultValue;

  for (const fieldName of fieldNames) {
    if (obj[fieldName] !== undefined && obj[fieldName] !== null && obj[fieldName] !== '') {
      return obj[fieldName];
    }
  }

  return defaultValue;
}

function getPriorityEmoji(priorityText) {
  if (!priorityText) return CONFIG.priorityEmojis.medium;

  const text = priorityText.toLowerCase();

  for (const [level, emoji] of Object.entries(CONFIG.priorityEmojis)) {
    if (text.includes(level)) {
      return emoji;
    }
  }

  return CONFIG.priorityEmojis.medium;
}

function formatDate(dateString) {
  if (!dateString) return 'Unknown date';

  try {
    return new Date(dateString).toLocaleString('en-US', {
      dateStyle: 'medium',
      timeStyle: 'short'
    });
  } catch {
    return dateString;
  }
}

function cleanText(text) {
  if (!text) return '';
  return String(text).trim();
}

// ============================================
// GET DATA FROM NODES
// ============================================
let emailData = getNodeData(CONFIG.emailNodeName);
let agentData = getNodeData(CONFIG.agentNodeName);

if (!emailData) {
  const inputData = $input.first().json;
  emailData = inputData.output || inputData;
}

if (!agentData) {
  agentData = {};
}

// ============================================
// EXTRACT VALUES (INCLUDING UID)
// ============================================
const data = {
  uid: cleanText(getField(emailData, CONFIG.fieldMappings.uid, 'N/A')),
  priority: cleanText(getField(emailData, CONFIG.fieldMappings.priority, 'Medium')),
  score: parseFloat(getField(emailData, CONFIG.fieldMappings.score, 0)) || 0,
  summary: cleanText(getField(emailData, CONFIG.fieldMappings.summary, 'No summary available')),
  suggestedReply: cleanText(getField(emailData, CONFIG.fieldMappings.suggestedReply, 'No suggested reply')),
  subject: cleanText(getField(emailData, CONFIG.fieldMappings.subject, 'No Subject')),
  emailBody: cleanText(getField(emailData, CONFIG.fieldMappings.emailBody, 'No content available')),
  fromName: cleanText(getField(emailData, CONFIG.fieldMappings.fromName, 'Unknown Sender')),
  fromEmail: cleanText(getField(emailData, CONFIG.fieldMappings.fromEmail, 'unknown@email.com')),
  receivedAt: getField(emailData, CONFIG.fieldMappings.receivedAt, new Date().toISOString()),
  emailType: cleanText(getField(emailData, CONFIG.fieldMappings.emailType, 'general')),
  agentId: cleanText(getField(agentData, CONFIG.fieldMappings.agentId, '')),
  phoneNumber: cleanText(getField(agentData, CONFIG.fieldMappings.phoneNumber, CONFIG.defaultPhone)),
  agentName: cleanText(getField(agentData, CONFIG.fieldMappings.agentName, 'WhatsApp Bot'))
};

data.priorityEmoji = getPriorityEmoji(data.priority);
data.priorityWithEmoji = `${data.priorityEmoji} ${data.priority}`;

// ============================================
// BUILD MESSAGE WITH UID AT THE TOP
// ============================================
const messageText = `📧 *IMPORTANT EMAIL NOTIFICATION*

🆔 *EMAIL UID:* ${data.uid}

━━━━━━━━━━━━━━━━━━━━━━━━━
🎯 *PRIORITY:* ${data.priorityWithEmoji}
📊 *SCORE:* ${data.score}/10
📂 *TYPE:* ${data.emailType.toUpperCase().replace(/_/g, ' ')}
━━━━━━━━━━━━━━━━━━━━━━━━━

📝 *EXECUTIVE SUMMARY*
${data.summary}

━━━━━━━━━━━━━━━━━━━━━━━━━
📨 *EMAIL INFORMATION*

👤 *From:* ${data.fromName}
📧 *Email:* ${data.fromEmail}
📌 *Subject:* ${data.subject}
🕐 *Received:* ${formatDate(data.receivedAt)}

━━━━━━━━━━━━━━━━━━━━━━━━━
📄 *FULL EMAIL CONTENT*

${data.emailBody}

━━━━━━━━━━━━━━━━━━━━━━━━━
✍️ *SUGGESTED PROFESSIONAL REPLY*

${data.suggestedReply}

━━━━━━━━━━━━━━━━━━━━━━━━━
📝 *TO CREATE A DRAFT REPLY*

Type: *Create draft for ${data.uid}*

━━━━━━━━━━━━━━━━━━━━━━━━━
⚡ _Automated Email Triage System_`;

// ============================================
// CREATE PAYLOAD - MATCH API EXPECTATIONS
// ============================================
let phoneNumber = data.phoneNumber;

// Clean phone number - remove + if present
if (phoneNumber && phoneNumber.startsWith('+')) {
  phoneNumber = phoneNumber.substring(1);
}

const payload = {
  agentId: data.agentId,
  to: phoneNumber,
  message: messageText
};

// ============================================
// RETURN PAYLOAD DIRECTLY
// ============================================
return [{
  json: payload
}];

// Get the meeting data from the previous node (Check for Pending Meeting)
const meetingData = $input.first().json;

// Get the original message data from IF Reply? node
let messageData = {};
let agentId = null;

try {
  const replyData = $('IF Reply?').first().json;  // Fixed: removed trailing space
  messageData = replyData.originalMessage || {};
  agentId = replyData.originalMessage?.agentId || replyData.agentId;
} catch (e) {
  console.log('Could not access IF Reply? node:', e.message);
}

// Fallback: try to get data from Log Message to DB if IF Reply? fails
if (!agentId) {
  try {
    const logData = $('Log Message to DB').first().json;
    agentId = logData.agent_id || logData.agentId;
  } catch (e) {
    console.log('Could not access Log Message to DB node:', e.message);
  }
}

// Check if we have a pending meeting
const hasPendingMeeting = meetingData && meetingData.contact_phone;

// Return combined data
return [{
  json: {
    hasPendingMeeting: !!hasPendingMeeting,
    meeting: hasPendingMeeting ? meetingData : null,
    message: $('Prepare data').first().json.messageBody,
    agentId: $('Prepare data').first().json.originalMessage.messageData.agentId,

    // Additional useful data
    senderPhone: messageData.senderPhone || meetingData.contact_phone,
    messageText: messageData.message,
    timestamp: messageData.timestamp
  }
}];

// ============================================================================
// DAILY REPORT PAYLOAD GENERATOR (FAN-OUT, NO WRAPPERS)
// Generates: Contact acknowledgment + Owner notification
// ============================================================================

const input = $input.item.json;
const outputs = [];

// ---------------------------------------------------------------------------
// VALIDATION
// ---------------------------------------------------------------------------
if (!input.agent_id) {
  throw new Error('❌ agent_id is required');
}
if (!input.sender_phone) {
  throw new Error('❌ sender_phone is required');
}

// ---------------------------------------------------------------------------
// HELPER - FORMAT PHONE (NO + PREFIX)
// ---------------------------------------------------------------------------
function formatPhone(phone) {
  if (!phone) return '';
  // Remove all non-digit characters (including +)
  return phone.toString().replace(/\D/g, '');
}

// ---------------------------------------------------------------------------
// EXTRACT DATA
// ---------------------------------------------------------------------------
const agentId = input.agent_id;
const senderPhone = formatPhone(input.sender_phone);
const senderName = input.sender_name || 'Contact';
const ownerName = input.owner || 'Owner';
const projectTitle = input.project || 'the project';
const reportDate = input.report_date || new Date().toISOString().split('T')[0];
const summary = input.summary || '';
const fileName = input.file_name || 'report.pdf';

// Get owner phone
let ownerPhone = '';
if (input.owner_phone) {
  ownerPhone = formatPhone(input.owner_phone);
} else if (input.owner_id && /^\+?\d+$/.test(input.owner_id)) {
  ownerPhone = formatPhone(input.owner_id);
} else if (input.user_id && /^\+?\d+$/.test(input.user_id)) {
  ownerPhone = formatPhone($('When Executed by Another Workflow').first().json.originalMessage.agentData.agent_phone_number);
}

// ---------------------------------------------------------------------------
// FORMAT DATE
// ---------------------------------------------------------------------------
const formatDate = (dateStr) => {
  try {
    const date = new Date(dateStr);
    return date.toLocaleDateString('en-US', { 
      year: 'numeric', 
      month: 'long', 
      day: 'numeric' 
    });
  } catch (e) {
    return dateStr;
  }
};

const formattedDate = formatDate(reportDate);

// ---------------------------------------------------------------------------
// PAYLOAD 1: CONTACT ACKNOWLEDGMENT
// ---------------------------------------------------------------------------
const contactMessage = `✅ *Daily Report Received - Thank You!*

Dear ${senderName},

Your daily report for *${projectTitle}* dated *${formattedDate}* has been successfully received and forwarded to ${ownerName}.

Thank you for your timely and detailed submission!

*Document:* ${fileName}
*Status:* ✅ Processed Successfully

---
If you have any questions or need to submit corrections, please feel free to reach out.`;

outputs.push({
  json: {
    agentId: agentId,
    to: senderPhone,
    message: contactMessage
  }
});

// ---------------------------------------------------------------------------
// PAYLOAD 2: OWNER NOTIFICATION (SIMPLE FORMAT)
// ---------------------------------------------------------------------------
if (ownerPhone) {
  const ownerMessage = `Daily report, ${projectTitle}, ${summary}`;

  outputs.push({
    json: {
      agentId: agentId,
      to: ownerPhone,
      message: ownerMessage
    }
  });
}

// ---------------------------------------------------------------------------
// FINAL OUTPUT (MULTI-ITEM ARRAY)
// ---------------------------------------------------------------------------
return outputs;
